  @protected
  void cst_api_fill_to_wire_frb_bench_event(
    FrbBenchEvent apiObj,
    wire_cst_frb_bench_event wireObj,
  ) {
    if (apiObj is FrbBenchEvent_StateChanged) {
      var pre_from = cst_encode_String(apiObj.from);
      var pre_to = cst_encode_String(apiObj.to);
      wireObj.tag = 0;
      wireObj.kind.StateChanged.from = pre_from;
      wireObj.kind.StateChanged.to = pre_to;
      return;
    }
    if (apiObj is FrbBenchEvent_Sample) {
      var pre_field0 = cst_encode_box_autoadd_frb_resource_sample(
        apiObj.field0,
      );
      wireObj.tag = 1;
      wireObj.kind.Sample.field0 = pre_field0;
      return;
    }
    if (apiObj is FrbBenchEvent_Token) {
      var pre_index = cst_encode_u_32(apiObj.index);
      var pre_text = cst_encode_String(apiObj.text);
      wireObj.tag = 2;
      wireObj.kind.Token.index = pre_index;
      wireObj.kind.Token.text = pre_text;
      return;
    }
    if (apiObj is FrbBenchEvent_WatchdogWarn) {
      wireObj.tag = 3;
      return;
    }
    if (apiObj is FrbBenchEvent_WatchdogKill) {
      wireObj.tag = 4;
      return;
    }
    if (apiObj is FrbBenchEvent_RunFinished) {
      var pre_run_id = cst_encode_u_64(apiObj.runId);
      var pre_status = cst_encode_String(apiObj.status);
      var pre_result = cst_encode_opt_box_autoadd_frb_bench_result(
        apiObj.result,
      );
      wireObj.tag = 5;
      wireObj.kind.RunFinished.run_id = pre_run_id;
      wireObj.kind.RunFinished.status = pre_status;
      wireObj.kind.RunFinished.result = pre_result;
      return;
    }
    if (apiObj is FrbBenchEvent_Log) {
      var pre_level = cst_encode_String(apiObj.level);
      var pre_message = cst_encode_String(apiObj.message);
      wireObj.tag = 6;
      wireObj.kind.Log.level = pre_level;
      wireObj.kind.Log.message = pre_message;
      return;
    }
    if (apiObj is FrbBenchEvent_Progress) {
      var pre_message = cst_encode_String(apiObj.message);
      wireObj.tag = 7;
      wireObj.kind.Progress.message = pre_message;
      return;
    }
  }

